#include <stdio.h>
#include <stdlib.h>
static long low=0, range=1;
static int cc[2*200000];
static int radix=255;
static void put_bit(int bit,int ctx){
 int *c=cc+ctx*2;
 long split=range*(c[0]+1)/(c[0]+c[1]+2);
 if(bit){low+=split;range-=split;c[1]++;} else {range=split;c[0]++;}
 while(range<radix){ putchar((low>>24)&0xff); low=(low&0xffffff)*radix; range*=radix; }
}
static void put_integer(int value,int tmp,int ctx){
 int ans=value+(1<<tmp), bits[64], n=0, t=ans;
 while(t>0){bits[n++]=t&1;t>>=1;}
 int unary=n-tmp-1;
 int i;
 for(i=0;i<unary;i++) put_bit(0,tmp+1+i);
 put_bit(1,tmp+1+unary);
 for(i=n-1;i>=0;i--) put_bit(bits[i],ctx);
}
static void finish(){ while(range<radix){ putchar((low>>24)&0xff); low=(low&0xffffff)*radix; range*=radix; } }
