 FILE *in=fdopen(p[1],"wb"); if(!in){close(p[0]);close(p[1]);return -1;}
 fwrite(b,1,n,in); fflush(in); fclose(p[1]);
 FILE *out=fdopen(p[0],"rb");
 unsigned char r[16]; int got=0,ch;
 while((ch=fgetc(out))!=EOF && got<16) r[got++]=ch;
 fclose(out);
 return got==1 && r[0]==1;
}
int main(){
